INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (7, 5118061, 10118, "フリーマーケット会場", "青空の下で謁見", 2, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 0, 8, "ペコリーヌとの出会い", 1, 40, 20063115, 91002, 2834);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (7, 5118062, 10118, "フリーマーケット会場", "未来の騎空団\nマスコット？", 2, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 0, 8, "マホとの出会い", 1, 40, 20063115, 91002, 2835);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (7, 5118063, 10118, "ランドソル市街地", "お嬢さまからの\n緊急依頼", 2, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 0, 8, "アキノとの出会い", 1, 40, 20063115, 91002, 2837);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118064, 10118, "フリーマーケット会場", "黄金色の悩みごと", 2, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 0, 8, "ジュンとの出会い", 1, 40, 20063115, 91002, 4108402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118065, 10118, "フリーマーケット会場", "白熱！　格闘大会！", 2, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 0, 8, "カオリとの出会い", 1, 40, 20063115, 91002, 4107402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (16, 5118066, 10118, "オーエド町", "祭り太鼓はオーエドの華", 2, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 1, 8, "ニノンとの出会い", 1, 40, 20063115, 91002, 9000227);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (19, 5118067, 10118, "フリーマーケット会場", "人気者は遅れて\nやってくる", 3, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 0, 8, "スズナとの出会い", 1, 40, 20063115, 91002, 2101181);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118068, 10118, "ランドソル市街地", "巫女・ミーツ・魔法少女", 3, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 0, 8, "ナナカとの出会い", 1, 40, 20063115, 91002, 4109402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118069, 10118, "フリーマーケット会場", "ネズ耳は二度なくなる", 3, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 0, 8, "キャル＆コッコロとの出会い", 1, 40, 20063115, 91002, 4305402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118070, 10118, "ランドソル市街地", "この出会いにカンパイ！", 3, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 0, 8, "ユカリとの出会い", 1, 40, 20063115, 91002, 4101402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (18, 5118071, 10118, "ランドソル市街地", "陰陽アンサンブル", 3, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 0, 8, "アオイとの出会い", 1, 40, 20063115, 91002, 4106402);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (7, 5118072, 10118, "フリーマーケット会場", "運試し十番勝負！", 3, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 1, 8, "シノブとの出会い", 1, 40, 20063115, 91002, 2836);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (0, 5118600, 10118, 0, "彼女たちの新たな日常", 1, 0, 0, 0, "オープニング", 0, 0, 20063115, 0, 0);
